import { cityMapping } from "./cityMapping";

export async function fetchAirQuality(city: string) {
  const token = process.env.WAQI_API_TOKEN;
  if (!token) throw new Error("API token missing");

  const cityQuery = cityMapping[city as keyof typeof cityMapping] || city;
  const encodedCity = encodeURIComponent(cityQuery);

  try {
    const res = await fetch(
      `https://api.waqi.info/feed/${encodedCity}/?token=${token}`,
    );

    if (!res.ok) throw new Error("Network error");

    const data = await res.json();
    if (data.status !== "ok") {
      console.warn(`API error for ${city}: ${data.status}`);
      return null;
    }

    return data.data;
  } catch (err) {
    console.error(`Fetch failed for ${city}:`, err);
    return null;
  }
}
